mapper.select:
SELECT p.id AS party_id,
       p.capacity,
       p.current_member_count,
       p.price_per_member_snapshot,
       (
           SELECT COUNT(1)
           FROM party_member pm
           WHERE pm.party_id = p.id
             AND pm.role = #{memberRole}
             AND pm.status = #{pendingMemberStatus}
       ) AS pending_member_count,
       (
           SELECT COUNT(1)
           FROM party_member pm
                    INNER JOIN billing_key bk ON bk.user_id = pm.user_id
           WHERE pm.party_id = p.id
             AND pm.role = #{memberRole}
             AND pm.status = #{pendingMemberStatus}
             AND bk.status = #{billingKeyStatus}
       ) AS ready_billing_member_count
FROM party p
WHERE p.id = #{partyId}
    LIMIT 1
